import React from 'react';

function Footer() {
    return (
        <footer>
            <span className="footer-brand">Go Business</span>
            <nav aria-label="Footer">
                <a href="#">About</a>
                <a href="#">Privacy Policy</a>
            </nav>
            <span className="copyright">© 2024 Go Business</span>
        </footer>
    );
}

export default Footer;
